import socket
import logging


class TCPclient:

    def __init__(self):
        logging.basicConfig(filename='logs/tcp_client.log', level=logging.DEBUG)
        logging.getLogger().addHandler(logging.StreamHandler())
        self.gateway_address = ('localhost', 6341)

        self.send_header = b'\xcd\xef\x124x\x9a\xfe\xdc\x00\x00\x00\x02\x00\x00\x00\x00\x00\x00\x00'
        self.r_stat_header = b'\xcd\xef\x124x\x9a\xfe\xdc\x00\x00\x00\x03\x00\x00\x00\x00\x00\x00\x02'
        self.r_dat_header = b'\xcd\xef\x124x\x9a\xfe\xdc\x00\x00\x00\x01\x00\xff\x91\xe7\x03\xe8\x00'

        self.replies = {
            bytes.fromhex("cdef1234789afedc00000002000000000000001453595354454d203a2054454c4c20535441545553"): "",
            bytes.fromhex("cdef1234789afedc00000002000000000000000b4348414e4e454c203a2044"): "cdef1234789afedc0000000300000000000000024f4b",
            bytes.fromhex("cdef1234789afedc00000002000000000000000f4d4f54494f4e203a204e4f524d414c"): "cdef1234789afedc0000000300000000000000024f4b",
            bytes.fromhex("cdef1234789afedc0000000200000000000000165452414e534d495353494f4e203a20534c4944494e47"): "cdef1234789afedc0000000300000000000000024f4b",
            bytes.fromhex("cdef1234789afedc00000002000000000000001153595354454d203a205449412041544e32"): "cdef1234789afedc00000003000000000000000c4f4b203a20313030302e3030",
            bytes.fromhex("cdef1234789afedc00000002000000000000001a4143515549534954494f4e203a20424547494e20313030302e30"): "cdef1234789afedc00000003000000000000000c4f4b203a20313030302e3030",
            bytes.fromhex("cdef1234789afedc0000000200000000000000174143515549534954494f4e203a20415645524147452032"): "cdef1234789afedc0000000300000000000000064f4b203a2032",
            bytes.fromhex("cdef1234789afedc0000000200000000000000124143515549534954494f4e203a2053544f50"): "cdef1234789afedc0000000300000000000000024f4b",
            bytes.fromhex("cdef1234789afedc0000000200000000000000184143515549534954494f4e203a2052414e474520302e3030"): "cdef1234789afedc0000000300000000000000064f4b203a2035",
            bytes.fromhex("cdef1234789afedc0000000200000000000000174143515549534954494f4e203a20524553455420415647"): "cdef1234789afedc0000000300000000000000024f4b",
            bytes.fromhex("cdef1234789afedc0000000200000000000000194143515549534954494f4e203a2052414e47452035302e3030"): "cdef1234789afedc0000000300000000000000074f4b203a203530",
            bytes.fromhex("cdef1234789afedc00000002000000000000001253595354454d203a204d4f4e49544f522031"): "cdef1234789afedc0000000300000000000000104d4f4e2031203a20302e303030303030",
            # self.send_header + b'\x11'+ b"MON 1: -0.024058": "",
            # self.send_header + b'\x0a'+ b"LASER : ON": "",
            # self.send_header + b'\x0a'+ b"VOLT1 : ON": "",
            # self.send_header + b'\x13'+ b"ACQUISITION : START" : "",
        }

    def run(self):
        with socket.socket(socket.AF_INET, socket.SOCK_STREAM) as s:
            s.connect(self.gateway_address)
            data = s.recv(1024)
            while True:
                logging.debug(f"client received: {data}")
                logging.debug(f"client sends: {self.replies[data]}")
                s.send(bytes.fromhex(self.replies[data]))
                data = s.recv(1024)

if __name__ == "__main__":
    client = TCPclient()
    client.run()